import { createMiddleware } from '@vex_dev/sdk/ai';
import { generateText } from 'ai';

const vexMiddleware = createMiddleware({
  orgId: 'your_org_id',
  policies: {
    phiRedaction: {
      block: true,
      redactFields: ['name', 'ssn', 'medical_record_number']
    },
    medicalValidation: {
      require: {
        diagnosis: { schema: 'ICD-10' },
        confidence: { min: 0.85 }
      }
    }
  }
});

export async function generateDiagnosis(prompt: string, patientContext: any) {
  const { text } = await generateText({
    model: 'gpt-4o',
    prompt,
    middleware: vexMiddleware
  }, {
    data: { patientContext, auditTrail: true }
  });
  return text;
}

import { createStreamMiddleware } from '@vex_dev/sdk/ai';
import { streamText } from 'ai';

const streamGuard = createStreamMiddleware({
  orgId: 'your_org_id',
  hallucinationDetection: {
    medicalTerms: true,
    confidenceThreshold: 0.9,
    blockOnFailure: true
  },
  phiStreaming: { redactInline: true }
});

export async function streamMedicalAdvice(prompt: string) {
  const result = await streamText({
    model: 'claude-3-5-sonnet-20240620',
    prompt,
    middleware: streamGuard,
    maxTokens: 1000
  });

  return result.toAIStreamResponse();
}

import { createTRPCRouter } from '@vex_dev/sdk/ai/trpc';
import { tool } from 'ai';
import { z } from 'zod';

const medicalTools = tool({
  getLabResults: {
    description: 'Fetch validated lab results',
    parameters: z.object({
      patientId: z.string().regex(/^[A-Z]\d{6}$/)
    }),
    execute: async ({ patientId }) => {
      // Fetch from compliant EMR
      return { hemoglobin: 12.5, creatinine: 0.9 };
    }
  }
});

const router = createTRPCRouter({
  orgId: 'your_org_id',
  require: {
    toolValidation: true,
    auditClinicalDecisions: true
  }
});

export async function agentDiagnosis(patientData: any) {
  const result = await router.run({
    tools: medicalTools,
    prompt: 'Analyze labs and provide diagnosis',
    data: patientData
  });
  return result;
}
